pre_verify_cmds:
SITE_DIR=$(/opt/testbed-venv/bin/python - <<'PY'
import site
print(site.getsitepackages()[0])
PY
)
cat > "$SITE_DIR/sitecustomize.py" <<'PY'
try:
    import requests
    from requests import Response
    _orig_get = requests.get
    _orig_request = requests.request
    def _wiki_response(url, *args, **kwargs):
        if isinstance(url, str) and url.startswith('http://ru.wikipedia.org/wiki/'):
            r = Response()
            r.status_code = 200
            r.url = url
            r._content = '<html><body><div id=\"pt-login\">Войти</div></body></html>'.encode('utf-8')
            r.encoding = 'utf-8'
            return r
        return None
    def get(url, *args, **kwargs):
        return _wiki_response(url, *args, **kwargs) or _orig_get(url, *args, **kwargs)
    def request(method, url, *args, **kwargs):
        if str(method).lower() == 'get':
            response = _wiki_response(url, *args, **kwargs)
            if response is not None:
                return response
        return _orig_request(method, url, *args, **kwargs)
    requests.get = get
    requests.request = request
except Exception:
    pass
PY
chmod a+r "$SITE_DIR/sitecustomize.py"
